// Combine users with their recent alerts + ownership data
const usersAll = $('Get Active Users').all().map(i => i.json);
const alertsAll = $('Get Recent Alerts').all().map(i => i.json);

// Get per-person account ownership map
let accountsByPerson = {};
try {
  accountsByPerson = $('Parse Opp Teams').first().json.accountsByPerson || {};
} catch (e) {
  // Parse Opp Teams didn't execute — no ownership filtering available
}

// Filter out empty items
const users = usersAll.filter(u => u && u.id);
const alerts = alertsAll.filter(a => a && a.id);

// Group recent alerts by user_id
const alertsByUser = {};
for (const a of alerts) {
  if (!alertsByUser[a.user_id]) alertsByUser[a.user_id] = [];
  alertsByUser[a.user_id].push(a);
}

// Output one item per active user
const output = [];
for (const user of users) {
  if (user.onboarding_state !== 'complete') continue;

  // Derive rep name from email for scope-aware filtering
  const email = (user.email || '').toLowerCase();
  const repName = email.split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase());

  // Find this user's accounts from ownership data (match on name, case-insensitive)
  const repLower = repName.toLowerCase();
  const userAccounts = accountsByPerson[repLower] || [];

  output.push({
    json: {
      userId: user.id,
      slackUserId: user.slack_user_id,
      email: user.email,
      assistantName: user.assistant_name || 'Aria',
      assistantEmoji: user.assistant_emoji || ':robot_face:',
      organizationId: user.organization_id,
      digestScope: user.digest_scope || 'my_deals',
      repName,
      userAccounts,
      userAccountCount: userAccounts.length,
      recentAlerts: alertsByUser[user.id] || []
    }
  });
}

if (output.length === 0) {
  return [{ json: { skip: true, reason: 'No active users found' } }];
}

return output;

const user = $input.first().json;

if (user.skip) {
  return [{ json: { ...user, monitorPrompt: '', skip: true } }];
}

const today = new Date().toISOString().split('T')[0];
const scope = user.digestScope || 'my_deals';
const repName = user.repName || '';
const userAccounts = user.userAccounts || [];

let prompt;

if (scope === 'my_deals') {
  if (userAccounts.length === 0) {
    // No accounts found for this user — skip
    return [{ json: { ...user, monitorPrompt: '', skip: true, skipReason: 'No accounts found for ' + repName } }];
  }
  // IC/CSM scope — only check their specific accounts
  const accountList = userAccounts.map(a => `• ${a}`).join('\n');
  prompt = `Check these specific accounts for engagement gaps. For each account below, check if there has been any customer-facing activity (emails, meetings, or calls) in the past 5 or more days. Only check these accounts — they are the accounts where ${repName} is the owner or CSM:\n\n${accountList}\n\nToday's date is ${today}. Report any that have gone silent (5+ days with no activity).`;
} else if (scope === 'team_deals') {
  // Manager scope — their accounts + team members' accounts
  // userAccounts already includes accounts where this person is owner or CSM
  // For team scope, we'd ideally include reports' accounts too, but for now use their accounts
  if (userAccounts.length > 0) {
    const accountList = userAccounts.map(a => `• ${a}`).join('\n');
    prompt = `Check these accounts for engagement gaps. For each account below, check if there has been any customer-facing activity (emails, meetings, or calls) in the past 5 or more days:\n\n${accountList}\n\nToday's date is ${today}. Report any that have gone silent (5+ days with no activity).`;
  } else {
    prompt = `Check accounts for engagement gaps across my team. Which accounts with open opportunities have had no customer-facing activity (emails, meetings, or calls) in the past 5 or more days? Today's date is ${today}.`;
  }
} else {
  // Exec/pipeline scope — all accounts
  prompt = `Check all accounts for engagement gaps. Which accounts with open opportunities have had no customer-facing activity (emails, meetings, or calls) in the past 5 or more days? Today's date is ${today}.`;
}

return [{
  json: {
    ...user,
    monitorPrompt: prompt
  }
}];

const agentOutput = $('Silence Monitor Agent').first().json.output || '';
const userData = $('Build Monitor Prompt').first().json;
const recentAlerts = userData.recentAlerts || [];

// Get all muted accounts (fetched before the loop)
let allMutedAccounts = [];
try {
  allMutedAccounts = $('Fetch Muted Accounts').all().map(i => i.json);
} catch (e) { /* node didn't run */ }

// Build per-user muted set (check muted_until expiry)
const now = new Date();
const mutedSet = new Set();
for (const m of allMutedAccounts) {
  if (m.user_id !== userData.userId) continue;
  if (m.muted_until && new Date(m.muted_until) < now) continue; // snooze expired
  mutedSet.add((m.entity_name || '').toLowerCase());
}

// Extract JSON from agent response
let silentAccounts = [];
const jsonMatch = agentOutput.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[1]);
    silentAccounts = parsed.silent_accounts || [];
  } catch (e) {
    try {
      silentAccounts = JSON.parse(agentOutput).silent_accounts || [];
    } catch (e2) {}
  }
}

// Build set of recently alerted entities for cooldown check
const alertedSet = new Set();
for (const alert of recentAlerts) {
  alertedSet.add(alert.entity_name.toLowerCase());
}

// Reclassify 60+ day accounts as 'dead'
for (const a of silentAccounts) {
  if ((a.days_silent || 0) >= 60) {
    a.severity = 'dead';
  }
}

// Filter out muted and recently alerted accounts
const newAlerts = silentAccounts.filter(a => {
  const name = (a.account_name || '').toLowerCase();
  if (mutedSet.has(name)) return false;
  if (alertedSet.has(name)) return false;
  return true;
});

// Identify dead accounts to auto-mute after this alert
const autoMuteAccounts = newAlerts
  .filter(a => a.severity === 'dead')
  .map(a => ({
    user_id: userData.userId,
    organization_id: userData.organizationId,
    alert_type_id: 'silence_contract',
    entity_name: a.account_name,
    mute_reason: 'auto_dead',
    muted_at: now.toISOString()
  }));

return [{
  json: {
    ...userData,
    allDetected: silentAccounts,
    newAlerts,
    autoMuteAccounts,
    detectedCount: silentAccounts.length,
    newAlertCount: newAlerts.length
  }
}];

const data = $input.first().json;
const alerts = data.newAlerts || [];

if (alerts.length === 0) {
  return [{ json: { ...data, hasAlerts: false, alertBlocks: '[]', alertText: '' } }];
}

const severityEmoji = {
  dead: ':skull:',
  critical: ':red_circle:',
  warning: ':large_orange_circle:',
  info: ':large_blue_circle:'
};

// Sort: dead first, then critical, warning, info
const order = { dead: 0, critical: 1, warning: 2, info: 3 };
alerts.sort((a, b) => (order[a.severity] || 9) - (order[b.severity] || 9));

const blocks = [
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `:mag: *Silence Contract Alert*\n${alerts.length} account${alerts.length === 1 ? '' : 's'} need${alerts.length === 1 ? 's' : ''} attention:`
    }
  }
];

for (const a of alerts) {
  const emoji = severityEmoji[a.severity] || ':white_circle:';
  const lastType = a.last_activity_type || 'activity';
  const lastDate = a.last_activity_date || 'unknown';
  let line = `${emoji} *${a.account_name}* — ${a.days_silent} d silent`;
  if (lastDate !== 'unknown') {
    line += ` (last: ${lastDate})`;
  }

  // Slack overflow value has 75-char max. Use compact format: "action|accountName"
  const acctName = a.account_name;

  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: line },
    accessory: {
      type: "button",
      text: { type: "plain_text", text: "Draft ✉️" },
      action_id: "silence_overflow_" + blocks.length,
      value: ("fd|" + acctName).slice(0, 75)
    }
  });
}

blocks.push({
  type: "context",
  elements: [{ type: "mrkdwn", text: "Click Draft on any account to draft a re-engagement email." }]
});

// Enforce Slack limits
if (blocks.length > 50) blocks.length = 50;
for (const b of blocks) {
  if (b.text && b.text.text && b.text.text.length > 3000) {
    b.text.text = b.text.text.slice(0, 2997) + '...';
  }
}

let plainText = alerts.length + ' account' + (alerts.length === 1 ? '' : 's') + ' need attention in silence check';

return [{ json: { ...data, hasAlerts: true, alertBlocks: JSON.stringify(blocks), alertText: plainText } }];

const data = $('Build Alert Message').first().json;
